code.perFrame:
zoom = 0.999514;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
wave_a = 0;;
rot = 3.5  ;;
dx = sin(time*.5);;
dy = sin(time*.18) * 3  ;;
ob_r = 0.5 + cos(0.068*time) - time;;
ob_g = 0.5 - sin(0.067*time) - time;;
ob_b = 0.5 + tan(0.075*time) - time;;
ib_r = ob_r*1.001;;
ib_g = ob_g*1.001;;
ib_b = ob_b*1.001;;
decay = 0.9999;;
basstemp= bass + bass_att + bass_thresh;;
trebtemp= treb + treb_att + treb_thresh;;
trasstemp= (max(basstemp, trebtemp));;
trassave= (trasstemp/3);;
basst= max(bass + bass_att, treb + treb_att);;
trebb= min(basst + bass_thresh, basst + treb_thresh);;
midbeat= trebb/3;;
midtb= max(midbeat + mid, midbeat + mid_att);;
mtb= midtb/2.25;;
beetA= (max(treb, bass) + min(treb_att, bass_att)) /2;;
beetB= (max(mid, beetA) + min(mid_att, beetA*0.5)) /2;;
beetAB= (beetA+beetB)/2;;
beetC= (max(mid, treb) + min(mid_att, treb_att)) /2;;
beetD= (max(bass, beetC) + min(bass_att, beetC*0.5)) /2;;
beetCD= (beetC+beetD)/2;;
beet= (beetAB+beetCD) /2;;
madbeat= (trassave+mtb+beet) /3;

